import{_ as e}from"./plugin-vue_export-helper-c27b6911.js";import{o as a,c as s,a as t}from"./app-48fb384e.js";const l={},o=t(`<h1 id="ismerkedjunk-meg-az-sql-lel" tabindex="-1"><a class="header-anchor" href="#ismerkedjunk-meg-az-sql-lel" aria-hidden="true">#</a> Ismerkedjünk meg az SQL-lel</h1><div class="hint-container note"><p class="hint-container-title">Ennek a témakörnek az a célja, hogy</p><ul><li>megtudjuk, hogyan működik a SQL</li><li>kommunikálunk a SQL-lel</li><li>biztonságba helyezzük a SQL-ben tárolt adatokat</li></ul></div><p>Sok dinamikus weboldalhoz és alkalmazáshoz szükség van valamilyen adatbázisra. Az adatbázis olyan információkat tartalmazhat, melyeket a weboldal vagy alkalmazás megjelenít a felhasználó számára.<br> Az SQL a weboldalakon és alkalmazásokban leggyakrabban használt adatbázis, arra tervezték, hogy kicsi és gyors legyen, kimondottan a weboldalak és alkalmazások számára.</p><p>Mint ahogy említettem is ebben a témakörben megtanulod, hogy hogyan működik az SQL és megtudhatod, hogy hogyan kommunikálhatsz vele.</p><h3 id="ismerjuk-meg-az-sql-mukodeset" tabindex="-1"><a class="header-anchor" href="#ismerjuk-meg-az-sql-mukodeset" aria-hidden="true">#</a> Ismerjük meg az SQL működését</h3><p>Az SQL szerverből, adatbázisból épül fel. A szerver irányítja az adatbázis rendszert. Ez kezeli az összes adatbázis utasítást. Például ha szeretnél létrehozni egy új adatbázist akkor küldened kell egy üzenetet az SQL szervernek melyben megmondod, hogy csinálj egy új adatbázist <code>ujadatbazis</code> néven. Ekkor az SQL szerver létrehoz egy alkönyvtárat az adatkönyvtárban, az alkönyvtárat ellátja az <code>ujadatok</code> névvel és elhelyezi benne a szükséges fájlokat a megfelelő formátummal. Ha adatokat szeretnénk beszúrni ebbe az adatbázisba akkor ugyanígy egy üzenetet kell küldeni a szervernek melyben megmondod neki az adatokat és hogy hová szeretnéd elhelyezni azokat.</p><p>Ahhoz, hogy utasításokat tudj adni a szervernek futnia kell és várnia a kéréseket. A szerver általában úgy van beállítva, hogy elindul, amikor elindítod az XAMPP-ot - ha nem indulna el akkor manuálisan indítsuk el - és ezután fut.</p><h3 id="ismerkedjunk-meg-az-adatbazisok-strukturajaval" tabindex="-1"><a class="header-anchor" href="#ismerkedjunk-meg-az-adatbazisok-strukturajaval" aria-hidden="true">#</a> Ismerkedjünk meg az adatbázisok struktúrájával!</h3><p>Az SQL egy relációs adatbázis-kezelő rendszer - RDBMS vagyis Relational Database Management System. Az SQL szerver rengeteg adatbázist tud kezelni egyszerre. Valójában az is előfordulhat, hogy sok-sok ember különböző adatbázisait kezeli egyetlen SQL szerver. Minden adatbázis tartalmaz egy olyan szerkezetet mely arra szolgál, hogy az adatokat tárolja benne, illetve tartalmazza magukat az adatokat. Létezhetnek adatbázisok adatok nélkül is csak a teljesen üres struktúrával - melyek malmoznak és alig várják már, hogy adatokat tároljanak bennük. 😄</p><p>Egy adatbázisban egy vagy több táblában tárolhatsz adatokat. Mielőtt az adatokat elhelyezhetnéd bennük, létre kell hoznod az adatbázist és a táblákat is. Először egy üres adatbázist hozol létre. Ezután helyezheted el az adatbázisodban az üres táblákat.</p><p>Az adatbázistáblák olyan elrendezésűek, mint a táblázatok melyeket már megszokhattál hiszen sorokból és oszlopókból állnak. Minden <strong>sor</strong> az adatbázis egy egyedét képviseli, például egy számítógépet, egy könyvet vagy egy projektet. Minden <strong>oszlop</strong> egy információelemet tartalmaz az adott egyedről, például egy számítógép nevét, egy könyv címét vagy egy projekt kezdési dátumát. Azt a helyet, ahol egy adott sor és egy adott oszlop metszi egymást, a tábla egyedi celláját mezőnek nevezzük.</p><p>Az adatbázisok táblái között kapcsolatok is lehetnek. Egy tábla egyik sora gyakran kapcsolódik egy másik tábla több sorához. Lehet például egy olyan adatbázisod melyben a könyveidet tárolod. Ekkor lesz egy könyv táblád és egy szerző táblád. A szerző tábla egy rekordja egy olyan íróról is tárolhat információkat, aki a könyvtáblában szereplő könyv szerzője. Amikor kapcsolatban állnak egymással a tábláid az egyik táblában szerepeltetned kell egy olyan oszlopot, melynek adatai egy másik tábla oszlopában szereplő adatokhoz illeszkednek. Csak azután szúrhatsz be adatokat, ha ezt a szerkezetet létrehoztad.</p><h3 id="hogyan-kommunikaljunk-az-sql-lel" tabindex="-1"><a class="header-anchor" href="#hogyan-kommunikaljunk-az-sql-lel" aria-hidden="true">#</a> Hogyan kommunikáljunk az SQL-lel?</h3><p>Az adatbázissal kizárólag azokon az üzeneteken keresztül kommunikálhatsz, melyeket elküldesz az SQL szervernek. A szervernek értenie kell az utasításokat, melyeket elküldesz neki.<br> A kommunikációhoz a <code>strukturált lekérdezőnyelvet</code> - Structured Query Language azaz SQL - használhatod melyet, mint szabványos programozási nyelvet a legtöbb adatbázis-kezelő rendszer megért.</p><p>Ahhoz, hogy olyan kérést írhass a szervernek melyet megért, egy SQL utasítást kell összeállítanod, és el kell küldened az SQL szervernek. A következő részekben arról olvashatsz, hogy ezt hogyan teheted meg.</p><h3 id="hogyan-irjunk-sql-lekerdezeseket" tabindex="-1"><a class="header-anchor" href="#hogyan-irjunk-sql-lekerdezeseket" aria-hidden="true">#</a> Hogyan írjunk SQL lekérdezéseket?</h3><p>Az SQL nagyon közel áll az angol nyelvhez nagyrészt angol szavakból áll melyeket olyan szóláncokká kell összefűznöd melyek hasonlítanak egy angol mondathoz. Általában nem kell semmilyen &quot;misztikus&quot; szakszót ismerned ahhoz, hogy megírhass egy működő SQL lekérdezést. 😉</p><p>Minden utasítás első szava a neve, mely egy tevékenységet jelölő szó, - <em>egy ige</em> - amely megmondja az SQL-nek, hogy mit kell tennie. Az utasítások melyekről szót ejtünk:</p><ul><li><code>CREATE</code> - létrehoz</li><li><code>DROP</code> - eltávolít</li><li><code>ALTER</code> - módosít</li><li><code>SHOW</code> - mutat</li><li><code>INSERT</code> - beszúr</li><li><code>LOAD</code> - betölt</li><li><code>SELECT</code> - lekérdez</li><li><code>UPDATE</code> - frissít</li><li><code>DELETE</code> - töröl</li></ul><p>Ezek az alapvető szavak elegendőek ahhoz, hogy adatbázisokat hozz létre és kommunikálj velük.</p><p>Az utasítások neveit más szavak és kifejezések követik - ezek közül néhányat kötelező használnod néhányat nem - melyek azt mondják meg az SQL-nek, hogyan végezze el az adott tevékenységet. Azt például minden esetben meg kell mondanod az SQL-nek, hogy mit hozzon létre és azt is mindig meg kell mondanod neki, hogy melyik táblába szúrjon be vagy melyikből kérdezzen le adatokat.</p><p>Alább egy mindennapi SQL utasítást láthatsz, mely angol szavakat használ:</p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">SELECT</span> vezeteknev 
<span class="token keyword">FROM</span> Tag
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p>Ha egy utasításban a <code>SELECT</code> szót használod, azt lekérdezésnek nevezzük, mert ilyenkor információkat kérsz le az adatbázisból. A lekérdezés ekkor visszaad minden, a <code>Tag</code> nevű táblában tárolt vezetéknevet. Az alábbi példában egy olyan összetett lekérdezést látsz, ami kevésbé hasonlít egy angol mondatra:</p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">SELECT</span> vezeteknev<span class="token punctuation">,</span> keresztnev 
<span class="token keyword">FROM</span> Tag 
<span class="token keyword">WHERE</span> megye <span class="token operator">=</span> <span class="token string">&quot;BAZ&quot;</span> <span class="token operator">AND</span> varos <span class="token operator">=</span> <span class="token string">&quot;Miskolc&quot;</span> 
<span class="token keyword">ORDER</span> <span class="token keyword">BY</span> vezeteknev
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>Ez a lekérdezés azoknak az embereknek a keresztnevét adja vissza, akik Miskolcon laknak, és a vezetéknevük szerint ábécésorrendben rendezi őket - habár ez a lekérdezés kevésbé hasonlít egy mondatra azért elég egyértelmű.</p><div class="hint-container tip"><p class="hint-container-title">Most pedig olvashatsz néhány általános dolgot melyeket észben kell tartanod, amikor SQL utasításokat készítesz, ahogy azt az előző egyszerű lekérdezésekben is láthattad:</p><p><strong>Nagybetűk használata:</strong> az SQL nyelvben szavakat nagybetűkkel írjuk. A változó elemek általában kisbetűkből állnak. Ezt azért csináljuk így, hogy az utasítások könnyebben olvashatók legyenek számunkra.<br> Az SQL szavai nem érzékenyek a kis és nagybetűkre, ha például azt írod le, hogy <code>select</code> az ugyanazt jelenti, mint a <code>SELECT</code> . A <code>from</code> is megegyezik azzal, hogy <code>FROM</code>, az SQL nem tesz köztük különbséget.</p><p>Másrészt viszont a táblanevek, oszlopnevek és más változók nevei érzékenyek a kis és nagybetűkre. Ha UNIX-ot használsz, az SQL-nek pontosan kell egyeztetnie az oszlopneveket, szóval az oszlopnevek kis és nagybetűit megfelelően kell használnod - így például a <code>vezeteknev</code> nem ugyanaz, mint a <code>vezetekNev</code>. A Windows azonban nem olyan válogatós, mint a UNIX, az ő szemszögéből a <code>vezeteknev</code> és a <code>vezetekNev</code> ugyanaz.</p><p><strong>Szóközök:</strong> Az SQL szavait egy vagy több szóközzel kell elválasztanod egymástól. Teljesen mindegy, hogy hány szóközt használsz, a két szó között lehet akár 20 is, vagy csak 1. Az SQL emellett a sorok végével sem törődik. Az SQL utasításokat bármely pontján kezdhetsz új sort vagy beírhatod az egész utasítást egyetlen sorba is.</p><p><strong>Idézés:</strong> Figyeld meg, hogy az előző lekérdezésben a <code>BAZ</code> és a <code>Miskolc</code> idézőjelek között szerepelnek (&quot;). A <code>BAZ</code> és a <code>Miskolc</code> karaktersorozatok, melyeket szöveges sztringeknek vagy karakter sztringeknek nevezünk. Itt azt kérjük az SQL-től, hogy az SQL lekérdezésben szereplő szöveges sztringet hasonlítsa össze azokkal a sztringekkel, melyeket már eltároltál az adatbázisban.<br> Amikor számokat hasonlítasz össze, a számokat ne tedd idézőjelek közé.</p></div><h3 id="hogyan-vedjuk-meg-a-sql-adatbazisunkat" tabindex="-1"><a class="header-anchor" href="#hogyan-vedjuk-meg-a-sql-adatbazisunkat" aria-hidden="true">#</a> Hogyan védjük meg a SQL adatbázisunkat?</h3><p>Az adatbázisodban található információkhoz való hozzáférést szabályoznod kell. El kell döntened, hogy ki láthatja az adataidat és ki módosíthatja azokat. Ha valaki megszerzi a vásárlóid privát információinak listáját, akkor nagy gondban leszel. Vigyáznod kell az adataidra!</p><p>Az SQL különböző védelmi eszközöket biztosít, hogy megvédhesd az adataidat.</p><div class="hint-container tip"><p class="hint-container-title">A következőket találhatod a rendszerben:</p><p><strong>SQL-fiókok:</strong> Senki nem férhet hozzá az adatokhoz az adatbázisodban ha nincs fiókja hozzá. Minden fióknak van egy neve, melyeket a felhasználónak használnia kell. A fiókhoz tartozik egy jelszó is, melyet a felhasználónak meg kell adnia ahhoz, hogy beléphessen a fiókjába. Emellett minden egyes fiók meghatározza, hogy honnan lehet hozzáférni az adataihoz. Például csak az aktuális számítógépről vagy egy meghatározott tartományból.</p><p><strong>Jogosultságok:</strong> Az SQL a fiókokhoz jogosultságokat határoz meg és ezekkel szabályozza, hogy ki mit tehet. Bárki, aki egy érvényes fiókot használ kapcsolódhat az SQL szerverhez de csak azokat a dolgokat teheti meg melyeket a fiókja jogosultságai lehetővé tesznek számára. Beállíthatsz például egy fiókot úgy, hogy a felhasználók lekérdezhessék az adatokat, de ne szúrhassanak be új információkat vagy frissíthessék a meglévőket. Úgy is beállíthatsz egy fiókot, hogy egy adott táblában módosíthassa az adatokat, viszont az összes többi táblában viszont csak olvashassa az adatokat.</p></div><p>Az SQL parancsok segítségével felhasználói fiókokat hozhatsz létre és törölhetsz, felvehetsz hozzájuk jelszót vagy módosíthatod azt. Jogosultságokat adhatsz nekik vagy vehetsz el tőlük. Ezeket a parancsokat az előző részben leírt mindkét módszerrel elküldheted. Az SQL fiókjaidat a <strong>phpMyAdmin</strong> funkcióinak segítségével kezelheted.</p><h2 id="sql-adminisztralasa" tabindex="-1"><a class="header-anchor" href="#sql-adminisztralasa" aria-hidden="true">#</a> SQL adminisztrálása</h2><div class="hint-container tip"><p class="hint-container-title">Ennek a témakörnek az a célja, hogy</p><ul><li>adminisztráljuk az SQL-t</li><li>felépítjük és felügyeljük a hozzáférést az adatokhoz</li><li>felhasználói fiókokat hozunk létre és kezelünk</li></ul></div><p>Ahogy arról már korábban volt szó az phpMyAdmin egy adatbáziskezelő szoftver. Olyan adatbázisokat kezel melyek azokat az adatokat tartalmazzák, amelyekre szüksége van az alkalmazásod felépítéséhez.<br> Az a cél, hogy adatokat tárolj az adatbázisban vagy pedig, hogy lekérj belőle.</p><p>A továbbiakban az SQL adminisztrációjával fogunk foglalkozni és megnézzük, hogyan szabályozhatod a hozzáférést az adataidhoz felhasználónevekkel és jelszavakkal, hogyan hozhatsz létre fiókokat és módosíthatod a jelszavakat és a jogosultságokat.</p><h3 id="az-adminisztratori-feladatok" tabindex="-1"><a class="header-anchor" href="#az-adminisztratori-feladatok" aria-hidden="true">#</a> Az adminisztrátori feladatok</h3><p>Az SQL adminisztrátori feladatoknak az a funkciója, hogy az SQL hatékonyan és biztonságosan láthassa el az adatbáziskezelés feladatát.<br> Ha egy webtárhely szolgáltató cég számítógépén használod az SQL-t akkor a legtöbb adminisztratív feladatot a tárhely szolgáltató látja el, viszont ha a saját számítógépeden használod akkor te vagy az adminisztrátor és teljes egészében te felelsz az adatbázisod adminisztrációjáért.</p><div class="hint-container warning"><p class="hint-container-title">Note</p><p>Nézzük pontokba szedve az adminisztrátor feladatait:</p><ul><li>SQL telepítése</li><li>SQL szerver elindítása és leállítása</li><li>SQL felhasználói fiókok létrehozása és karbantartása</li><li>Biztonsági mentések készítése az adatokról.</li><li>SQL frissítése</li></ul></div><h3 id="alapertelmezett-hozzaferes-az-adatokhoz" tabindex="-1"><a class="header-anchor" href="#alapertelmezett-hozzaferes-az-adatokhoz" aria-hidden="true">#</a> Alapértelmezett hozzáférés az adatokhoz</h3><p>Az SQL telepítése során egy alapértelmezett <code>root</code> nevű fiókot kapsz. Ez a fiók néha jelszó nélkül van létrehozva. Éles környezetben sose használd a <code>root</code> fiókot jelszó nélkül!<br> Ha telepítés során egy olyan fiók jött létre, melyhez nem tartozik jelszó akkor azonnal adj meg hozzá egy jelszót. A <code>root</code> fiók úgy van beállítva, hogy minden lehetséges jogosultsággal rendelkezik. Ezt a fiókot használhatod az adatbázisod adminisztrációjához. Nem lesz szükséged arra a fiókra mely minden jogosultsággal rendelkezik, hogy hozzáférj az adatbázisodhoz vagy adatokat tárolj és kérj le. Így legtöbb esetben szükséged lesz egy olyan fiókra melynek kevesebb jogosultsága van és amellyel hozzáférhetsz az adataidhoz.</p><h3 id="adatokhoz-valo-hozzaferes-szabalyozasa" tabindex="-1"><a class="header-anchor" href="#adatokhoz-valo-hozzaferes-szabalyozasa" aria-hidden="true">#</a> Adatokhoz való hozzáférés szabályozása</h3><p>El kell döntened, hogy ki láthatja és módosíthatja az adatokat. Képzeld el, hogy mi történne, ha bárki módosítani tudná az információkat az adatbázisodban vagy le tudnák másolni azt - pillanatok alatt tönkremenne a munkád. Nyilvánvaló, hogy az adataidra vigyáznod kell!</p><div class="hint-container warning"><p class="hint-container-title">Ezért kell használnod az SQL biztonsági rendszerét. Minden fiók rendelkezik a következő tulajdonságokkal:</p><ul><li>felhasználónév,</li><li>számítógépnév, amelyről az adott fiókkal hozzá lehet férni az SQL szerverhez</li><li>jelszó,</li><li>jogosultságok listája.</li></ul></div><p>Ahhoz, hogy valaki hozzáférhessen az adatokhoz, érvényes fiókkal kell rendelkeznie és tudnia kell az ehhez a fiókhoz tartozó jelszót, illetve arról a számítógépről kell csatlakoznia,<br> melynek engedélyezve van, hogy csatlakozzon az adatbázishoz.</p><p>Minden fiók esetén megadható, hogy elvégezhet-e az adatbázison olyan műveleteket, mint például a <code>SELECT</code>, <code>DELETE</code>, <code>INSERT</code>, <code>CREATE</code>, <code>DROP</code> vagy ezek közül egyiket sem.</p><div class="hint-container tip"><p class="hint-container-title">Tips</p><p>Amikor egy felhasználó megpróbál csatlakozni az adatbázishoz majd lefuttat egy utasítást akkor két szinten szabályozza a hozzáférést az adatokhoz:</p><ol><li><p><strong>Kapcsolat ellenőrzése:</strong> Ellenőrzi, hogy a felhasználónév és a jelszó érvényes-e és azt is megnézi, hogy olyan számítógépről jön-e a kapcsolódási kísérlet melyről engedélyezett a csatlakozás az adatbázis szerverhez. Ha minden rendben van akkor megkísérli a csatlakozást.</p></li><li><p><strong>A kérés ellenőrzése:</strong> Megkísérel csatlakozni ellenőrzi, hogy az adott fiók rendelkezik-e megfelelő jogosultságokkal ahhoz, hogy végrehajtsa a megadott utasítást. Ha igen akkor végrehajtja az utasítást.</p></li></ol></div><p>Bármely utasításnak, melyet elküldesz lehet sikertelen a futása azért mert már az első lépésben visszautasítják a kapcsolatot vagy mert a második lépésben kiderül, hogy nincs jogosultságod az utasítás végrehajtásához. Ekkor egy hibaüzenetet kapsz vissza mely segít azonosítani a probléma forrását.</p><h3 id="felhasznalo-es-szamitogepnevek" tabindex="-1"><a class="header-anchor" href="#felhasznalo-es-szamitogepnevek" aria-hidden="true">#</a> Felhasználó és számítógépnevek</h3><p>A felhasználónév és a számítógépnév együtt azonosítanak egy egyedi fiókot. Az SQL szerver csak akkor fogadja a kéréseket ha egy fiókról és számítógépnévről csatlakozik.<br> Amikor a <code>GRANT</code> <em>- engedélyez -</em> vagy a <code>REVOKE</code> <em>- visszavon -</em> parancsokat használod akkor a fiókot felhasználónév és számítógépnév együttesével azonosítod, melynek a formátuma: <code>felhasznalonev@szamitogepnev</code> - például <code>root@localhost</code>.</p><div class="hint-container danger"><p class="hint-container-title">Az SQL fiók neve semmilyen módon nem függ össze a UNIX-os vagy Windows-os felhasználónevekkel.</p><p>Ha a <code>root</code> nevű adminisztrátori fiókot használod ennek a fióknak semmi köze a UNIX-os root felhasználódhoz. Ha módosítod a fiókodat az nem lesz hatással a <strong>UNIX</strong>-os vagy a <strong>Windows</strong>-os felhasználódra.</p></div><p>A SQL felhasználónevek és számítógépnevek a következő jellemzőkkel rendelkeznek:</p><ul><li>Egy fiók neve maximum 16 karakter hosszú lehet.</li><li>A felhasználónév lehet üres.</li><li>A számítógépnév lehet név vagy IP-cím.</li><li>A számítógépnév tartalmazhat <em>joker</em> karaktereket.</li><li>A számítógépnév lehet üres.</li></ul><p>Létrehozhatsz olyan fiókot is melynek a felhasználóneve és számítógépneve is üres. Egy ilyen fiókkal bármilyen felhasználónévvel bármelyik számítógépről bárki csatlakozhat a MySQL szerverhez. Ilyen fiókot biztosan nem szeretnél. 😉</p><p>Ha nem mondtam volna még amikor telepíted az SQL-t automatikusan létrehoz egy fiókot, mely az összes jogosultsággal rendelkezik, ez a <code>root@localhost</code> fiók.</p><h3 id="fiok-jogosultsagok" tabindex="-1"><a class="header-anchor" href="#fiok-jogosultsagok" aria-hidden="true">#</a> Fiók jogosultságok</h3><table><thead><tr><th>Jogosultság</th><th>Leírás</th></tr></thead><tbody><tr><td><code>ALL</code></td><td>Minden jogosultság</td></tr><tr><td><code>ALTER</code></td><td>Módosíthatja a táblák szerkezetét</td></tr><tr><td><code>CREATE</code></td><td>Létrehozhat új adatbázisokat és táblákat</td></tr><tr><td><code>DELETE</code></td><td>Törölheti a táblák sorait</td></tr><tr><td><code>DROP</code></td><td>Eltávolíthat adatbázisokat és táblákat</td></tr><tr><td><code>FILE</code></td><td>A szerveren beolvashat fájlokat és írhat fájlokba</td></tr><tr><td><code>GRANT</code></td><td>Módosíthatja egy fiók jogosultságait</td></tr><tr><td><code>INSERT</code></td><td>Új sorokat szúrhat be táblákba</td></tr><tr><td><code>SELECT</code></td><td>Olvashatja a táblák adatait</td></tr><tr><td><code>SHUTDOWN</code></td><td>Leállíthatja a szervert</td></tr><tr><td><code>UPDATE</code></td><td>Módosíthatja egy tábla meglévő adatait</td></tr><tr><td><code>USAGE</code></td><td>Nem tartozik hozzá jogosultság</td></tr></tbody></table><div class="hint-container danger"><p class="hint-container-title">ALL jogosultság</p><p><code>ALL</code> jogosultságokat bizonyára nem szeretnél adni senkinek, mivel ez tartalmazza az olyan adminisztratív műveletek jogosultságait is, mint például a szerver leállítása.</p></div><p>Az összes fiók neve a <code>mysql</code> nevű adatbázisban a <code>user</code> táblában van eltárolva. Ha szeretnéd látni a fiókok információit, lefuttathatod a következő lekérdezést a <code>mysql</code> adatbázison:</p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">SELECT</span> <span class="token operator">*</span> <span class="token keyword">FROM</span> <span class="token keyword">user</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>Ekkor a fiókok egy listáját kell látnod. Ha azonban a szolgáltatódnál férsz hozzá akkor valószínűleg nincsenek meg a megfelelő jogosultságaid ehhez. Ebben az esetben egy a következőhöz hasonló hibaüzenetet fogsz kapni.</p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">No</span> <span class="token keyword">Database</span> Selected
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>Az üzenet annyit jelent, hogy a fiókodból nem kérdezhetsz le a <code>mysql</code> adatbázisból. Esetleg kaphatsz egy olyan hibaüzenetet is, mely azt mondja, hogy nincs jogosultságod a <code>SELECT</code> utasítás futtatásához.</p><h3 id="fiokok-letrehozasa" tabindex="-1"><a class="header-anchor" href="#fiokok-letrehozasa" aria-hidden="true">#</a> Fiókok létrehozása</h3><p>A megfelelő módszer az adatbázisod eléréséhez egy fiók létrehozása külön erre a célra azokkal a jogosultságokkal, melyekre szükséged van. Ha egy vagy több fiókot szeretnél létrehozni és megvannak hozzá a szükséges jogosultságaid akkor használd a <code>CREATE USER</code> parancsot a következőképpen:</p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">CREATE</span> <span class="token keyword">USER</span> felhasznalonev<span class="token variable">@szamitogepnev</span> IDENTIFIED <span class="token keyword">BY</span> <span class="token string">&#39;jelszo&#39;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>Ez az utasítás létrehozza a megadott felhasználói fiókot a hozzá meghatározott jelszóval és jogosultságok nélkül. Ha kihagyod az <code>IDENTIFIED BY &#39;jelszo&#39;</code> részt a fiók jelszó nélkül jön létre. Később bármikor megadhatsz egy jelszót a fiókhoz vagy módosíthatod a meglévő jelszavát.</p><div class="hint-container tip"><p class="hint-container-title">Karakterkészletek és magyar ékezetes karakterek kezelése</p><p>Az SQL alapértelmezés szerint <strong>ASCII</strong> karakterkódolást használ, mely nem támogatja a magyar ékezetes betűk használatát, ezért ha az alapbeállítások mellett ékezetes felhasználóneveket adsz meg, az ékezetes betűk helyén <code>?</code> karakterek fognak megjelenni.</p><p>Ezt orvosolhatod, ha olyan karakterkészletet állítasz be mely támogatja a magyar ékezetes karaktereket, például az <strong>UTF-8</strong>.</p></div><h3 id="fiokjelszavak-modositasa" tabindex="-1"><a class="header-anchor" href="#fiokjelszavak-modositasa" aria-hidden="true">#</a> Fiókjelszavak módosítása</h3><p>A jelszavak nincsenek &quot;kőbe vésve&quot;. A meglévő fiókokban is adhatsz meg vagy módosíthatsz jelszót. Mint bármely más eljárásnál a jelszavak megadásához vagy módosításához is használhatsz SQL utasítást a következőképpen:</p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">SET</span> PASSWORD <span class="token keyword">FOR</span> felhasznalonev<span class="token variable">@szamitogepnev</span> <span class="token operator">=</span> PASSWORD<span class="token punctuation">(</span><span class="token string">&#39;jelszo&#39;</span><span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>Ezzel a <code>felhasznalonev@szamitogepnev</code> fiókhoz a <code>jelszo</code> jelszót állítottad be. Ha a fiók már rendelkezik jelszóval, akkor lecseréled vele a meglévőt. Ha nem adod meg a <code>FOR</code> kulcsszót akkor a jelszó ahhoz a fiókhoz kerül beállításra, amelyet éppen használsz.</p><p>Úgy távolíthatsz el meglévő jelszót, ha a <code>SET PASSWORD</code> utasítást üres jelszóval adod ki:</p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">SET</span> PASSWORD <span class="token keyword">FOR</span> felhasznalonev<span class="token variable">@szamitogepnev</span> <span class="token operator">=</span> PASSWORD<span class="token punctuation">(</span><span class="token string">&#39;&#39;</span><span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><div class="hint-container danger"><p class="hint-container-title">Amikor jelszavakat módosítasz, frissítened kell a jogosultságokat ahhoz, hogy érzékelje a változásokat.</p><p>Ezt a <code>FLUSH PRIVILEGES</code> utasítással oldhatod meg.</p></div><h3 id="fiok-jogosultsagok-modositasa" tabindex="-1"><a class="header-anchor" href="#fiok-jogosultsagok-modositasa" aria-hidden="true">#</a> Fiók jogosultságok módosítása</h3><p>Minden fiók rendelkezik egy jogosultsági körrel, mely meghatározza, hogy a fiók használója mit tehet és mit nem. A jogosultságokat akkor állíthatod be amikor létrehozod a fiókot, de később is bármikor módosíthatod őket. A fiókok aktuális jogosultságait a következő utasítással kérheted le:</p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">SHOW</span> GRANTS <span class="token keyword">ON</span> felhasznalonev<span class="token variable">@szamitogepnev</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>Ennek a kimenete egy <code>GRANT</code> utasítás lesz, mely létrehozná a fiókot az aktuális állapotában. A kimeneten láthatod az összes jogosultságot. Ha nem adod meg az <code>ON</code> kulcsszót akkor annak a fióknak fogod látni az aktuális jogosultságait mellyel kiadtad a <code>SHOW GRANTS</code> utasítást.</p><p>Egy fiók jogosultságait a <code>GRANT</code> utasítás segítségével módosíthatod, melynek a következő az általános formátuma:</p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">GRANT</span> jogosultsag <span class="token punctuation">(</span>oszlopok<span class="token punctuation">)</span> <span class="token keyword">ON</span> tablanev 
<span class="token keyword">TO</span> felhasznalonev<span class="token variable">@szamitogepnev</span> IDENTIFIED <span class="token keyword">BY</span> <span class="token string">&#39;jelszo&#39;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p>Mint minden jogosultságokhoz kötődő módosítás esetén a jogosultságokat a módosítások után itt is frissítened kell, a <code>FLUSH PRIVILEGES</code> segítségével.</p><p>A <code>GRANT</code> utasítás segítségével egy új fiókot is létrehozhatsz vagy módosíthatsz egy jelszót. Használatához a következő információkat kell megadnod:</p><ul><li><p><strong>Jogosultság:</strong> Legalább egy jogosultságot meg kell adnod. Minden jogosultságot korlátozhatsz egy vagy több oszlopra is, ha megadod az oszlopneveket zárójelek között a jogosultság megadása után. Ha nem adsz meg oszlopnevet, akkor a jogosultság a tábla vagy táblák összes oszlopára ki lesz adva. Annyi jogosultságot és oszlopot adhatsz meg, amennyire csak szükséged van, vesszőkkel elválasztva.</p></li><li><p><strong>Táblanév:</strong> Azon tábla (vagy táblák) neve (vagy nevei), melyekre megadod a jogosultságot. Legalább egy táblát meg kell adnod. Számos táblát megadhatsz, vesszőkkel elválasztva. A táblanév lehetséges értékei a következők:</p><ul><li><code>táblanév</code>: Az egész <code>táblanév</code> nevű tábla az aktuális adatbázisban. Használhatsz csillagot is <em>(*)</em>, mely az aktuális adatbázis összes táblájára hivatkozik. Ha csillagot használsz, és nincs kiválasztva adatbázis, akkor a jogosultságot az összes adatbázis összes táblájára adod ki.</li><li><code>adatbázisnév.táblanév</code>: Az egész, <code>táblanév</code> nevű tábla az <code>adatbázisnév</code> nevű adatbázisban. Használhatsz csillagot is <em>(*)</em> az adatbázis vagy a tábla neve helyett is az összes adatbázisra, vagy az összes táblára hivatkozva. A * . * jelöléssel a jogosultságot az összes adatbázis összes táblájára adhatod ki.</li></ul></li><li><p><strong>felhasznalonev@szamitogepnev:</strong> Ha a felhasználói fiók már létezik, akkor megkapja a megadott jogosultságokat. Ha a fiók még nem létezik, akkor létrejön. A fiókot a <code>felhasználónév</code> és<br><code>számítógépnév</code> pár azonosítja. Ha már létezik fiók a megadott felhasználónévvel, de más számítógépnévvel, akkor a meglévő fiók nem módosul és egy új fog létrejönni.</p></li><li><p><strong>Jelszó:</strong> A jelszó, melyet megadsz vagy módosítasz. Nem kötelező jelszót megadnod. Ha nem akarsz jelszót megadni vagy a meglévő jelszót módosítani az adott fiókhoz akkor hagyd ki az <code>IDENTIFIED BY &#39;jelszo&#39;</code> részt.</p></li></ul><p>Az a <code>GRANT</code> utasítás amellyel létrehozol egy új felhasználót ahhoz, hogy egy <code>Termekek</code> nevű adatbázist használhassa a következőképpen nézhet ki:</p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">GRANT</span> <span class="token keyword">SELECT</span> <span class="token keyword">ON</span> Termekek<span class="token punctuation">.</span><span class="token operator">*</span> <span class="token keyword">TO</span> felhasznalonev<span class="token variable">@localhost</span> IDENTIFIED <span class="token keyword">BY</span> <span class="token string">&#39;jelszo&#39;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>Ha jogosultságokat szeretnél visszavonni, akkor használd a <code>REVOKE</code> utasítást. Ennek általános formátuma a következő:</p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">REVOKE</span> jogosultsag <span class="token keyword">ON</span> tablanev <span class="token keyword">FROM</span> felhasznalonev<span class="token variable">@szamitogepnev</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>Meg kell adnod a megfelelő információkat.</p><p>A következő <code>REVOKE</code> utasítással minden jogosultságot visszavonhatsz egy fióktól:</p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">REVOKE</span> <span class="token keyword">ALL</span> <span class="token keyword">ON</span> <span class="token operator">*</span><span class="token punctuation">.</span><span class="token operator">*</span> <span class="token keyword">FROM</span> felhasznalonev<span class="token variable">@szamitogepnev</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h3 id="fiok-torlese" tabindex="-1"><a class="header-anchor" href="#fiok-torlese" aria-hidden="true">#</a> Fiók törlése</h3><p>Elképzelhető, hogy a jövőben törölnöd kell majd egy fiókot, ezért a legtöbb esetben, ha van egy olyan fiók már amit senki sem használ akkor a törlés nem árt senkinek se. Ha azonban úgy gondolod, hogy egy fiókot feltörtek, akkor lehet, hogy biztonsági okokból törölni szeretnéd.</p><p>Felhasználói fiókokat a <code>DROP USER</code> utasítás segítségével törölhetsz a következőképpen:</p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">DROP</span> <span class="token keyword">USER</span> felhasznalonev<span class="token variable">@szamitogepnev</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>Ehhez olyan fiókot kell használnod, mely rendelkezik <code>DELETE</code> jogosultsággal a <code>mysql</code> adatbázisban, mert csak az tudja lefuttatni a <code>DROP USER</code> utasítást.</p>`,96),n=[o];function z(k,d){return a(),s("div",null,n)}const g=e(l,[["render",z],["__file","lesson1.html.vue"]]);export{g as default};
